INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "プリンセスなプリンなの\nお店にあったいろんな食べもの\nを入れられるだけ入れてみたの\nどんな味なのか楽しみなの", "やばいですね☆なの！", 3, 100, 1, "おいしすぎて食べ始めたら\n止まらない最高のプリンなの\n今のミヤコを止められるヤツは\n誰もいないの", "ペコリーヌのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "いつもオマエのそばに寄りそう\nヤツのぷりんなの。ミヤコの\nワガママもやさしく受け入れて\nくれそうなの", "主さま、なの！", 3, 101, 2, "なんだかすごくやさしい気持ち\nになる味なの…\nおはようからおやすみまで\nずっと一緒な味なの…", "コッコロのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (0, 5, "ツンツンデレデレなヤツの\nプリンなの。砂糖とスパイスを\n混ぜてみたの。どんな味になる\nか楽しみなの", "ぶっ殺すぞ！なの！\n…デレデレはどこなの？", 3, 102, 3, "いろんな味が一度で楽しめる\nプリンなの。ツンデレはプリン\nにするとおいしいの。ミヤコも\nツンデレを目指してみるの", "キャルのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "オマエと同じで、一度赤ちゃん\nみたいになったヤツのプリン\nなの。ヒンヤリ、プリンアイス\nにしてみたの", "おにーたん♪なの！", 3, 103, 4, "あったかいところで食べる\nプリンアイスは最高なの～♪\n安心しすぎて昔の記憶のない\nミヤコも心が子どもになるの～", "シェフィのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "イリヤを見てたら思いついた\nトマトジュースが隠し味の\nプリンなの。栄養満点なの", "ハーハッハッハ！\n世界征服なのじゃなのー！", 3, 104, 5, "トマトで栄養補給も完璧なの\nどんどん力がみなぎってきて\n復活も夢じゃないの\nミヤコが復活したら…", "イリヤのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "アカリのプリンなの。ヨリと\n同じくらいかわいく作って\nやったの。正直ミヤコは\nおいしければなんでもいいの", "お兄ちゃんのエッチ！　なの！", 3, 105, 6, "見た目がかわいくてもミヤコは\n味にも厳しいの。あむっ…\nこ、これは…！なんだかすごく\n変な気分になってきたの…", "アカリのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "かわいくつくらないとアカリが\n怒りそうだからヨリのプリンは\nかわいく作ったの。自信作なの", "えっと…その…あんたのこと…\nだ、大っ嫌いなのーー！", 3, 106, 7, "んむぅ…これはなかなか感想が\n難しいプリンなの…率直に言い\nたいような…心のうちに秘めて\nおきたいような…", "ヨリのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (0, 5, "シノブはいつもミヤコに\nやさしくしてくれるから\n丁寧に作ったの。ドクロ親父は\nいらないから作ってないの", "お父さん…\nいいかげんにしてなの！\nん？プリンの未来は…\n見えなかったの…", 3, 107, 8, "このプリンを食べるとシノブが\nミヤコの中にいるみたいなの！\nシノブの力があれば未来の\nプリンを見放題なの！", "シノブのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "黒い鎧を脱がないヤツのプリン\nなの。固めのプリンを目指したら\nカチカチになりすぎたの", "インフェルノシールド！なの！", 3, 108, 9, "固すぎてかじれないから丸吞み\nにしたの。なんだか体が硬く\nなった気がするの。みんなを\n守れる気がするの！", "ジュンのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "オマエをいっつもからかってる\nヤツのプリンなの\nちょっぴり変わったスパイスで\nからかいを表現したの", "あなたといると調子が狂うな\n…なの\n翻弄してたのはオマエなの？", 3, 109, 10, "口の中でスパイスがプチプチ\nはじけて新食感なの！\nプチプチがミヤコを\n翻弄するの！", "トモのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "王宮騎士団にいるちっこいヤツ\nなの。ちっこいけどやるヤツ\nらしいから、濃いめの味付けに\nしてみたの", "タイガーヒーローボンバー！\nなの！", 3, 110, 11, "ん～見かけによらず濃厚な\nパンチのある味わいが\n口いっぱいに広がるの！", "マツリのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "なんかすごくクールなプリンなの\nなんかテンションも少し\n低そうなの。これ\n食べちゃっても大丈夫なの？", "ま、いいんじゃん？\nしらんけどなの", 3, 111, 13, "クールな見た目なのにとっても\n優しい味なの！なんだか\n懐かしさを感じるの…", "クロエのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "きれいにデコれたの！\nカラフルでおいしそうなの\nこれは期待できそうなの", "ぷりーん★なの！", 3, 112, 14, "なんか変わった食感なの…\nちゃる…ちょる…ちぇる？\nちぇるってしてるの\nでもちぇるってなんなの？", "チエルのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "見た目は完ぺきなの！\nこれをつくったやつは\nきっと天才なの！\n早く食べたいの！", "端的に換言すれば\n青春の味なの？", 3, 113, 15, "味はなんか妙に\n甘酸っぱいの…\n食べたことない味なの\nこの味ってもしかして…", "ユニのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "オマエから聞いた懐かしい\n味ってヤツを全部入れてみたの\nオマエ記憶がないのに懐かしい\nってどういうことなの？", "幼なじみはあんた…なの？", 3, 114, 16, "ミヤコも幽霊になる前の記憶\nがないのに、なんだか懐かしい\n気持ちになってくるの…", "サレンのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "たまたま会ったメイドに教えて\nもらった作り方なの。メイドは\nプリンも作れるはずなの。\nなのにこの不安は何なの…？", "ひゃああんなの～！", 3, 115, 17, "おかしいの。このプリンを\n食べてから、３回も転んだの\nミヤコは幽霊だから転んだり\nしないの。なんでなの…？", "スズメのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (0, 5, "怖がりな子どもが教えてくれた\n小さくてかわいいプリンなの　\n触ってないのにぷるぷる震える\n驚きのやわらかさなの", "サルキデバレヤ！なの！", 3, 116, 18, "甘さのなかに少しのしょっぱさ\nクセになる味なの\nこのプリンはがんばればきっと\nいろんな美味しいになれるの", "クルミのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "くまのぬいぐるみを見ていたら\nひらめいたの。小さいけど\nしっかりした甘さの元気に\nなれるプリンなの！", "プリンフルスイングなの～！", 3, 117, 19, "このプリン、食べるとなんだか\nお姉ちゃんになった気分に\nなるの。ピンチのプリンは\nミヤコが守ってやるの！", "アヤネのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "マホマホ王国って国にいる\nお姫様のプリンなの\n魔物も虜にしちゃう\nすてきなプリンなの", "みらくるみやりん\nくるりんぱ～☆なの！", 3, 118, 20, "メルヘンパワーがあふれてきて\nいまならミヤコにも魔法が\n使える気がするの！\nほな、いきまひょ～なの！", "マホのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "カッコいいプリンを目指して\nワイルドなものをガンガン\n入れてみたの。きっと熱い\nプリンができるはずなの", "ウルフェンバイトなの！", 3, 119, 21, "うおーん！ミヤコなんだか\n強くなった気がするの！\n困ったことがあればミヤコが\nまとめて面倒見てやるの！", "マコトのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "どっかの国でよくとれる\nゴーヤーに似てるやつを\nいれてみたの！ちょっと\n苦いらしいけど…", "なんくるないさ～！なの！", 3, 120, 22, "一口食べたら元気が\nあふれて止まらないの！\n気分がいいから、一曲\n踊りでも披露してやるの！", "カオリのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "勘の鋭いやつが好きな食べ物を\nたくさん入れてみたの\n難しいこと考えるのにぴったり\nらしいけど、なんでなの？", "ふふん。簡単な推理なの", 3, 121, 23, "むむむ…なるほどなの\n上質な糖分をふんだんに\n使うことで、脳をより活性化\nできるからなの！", "カスミのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "搾りたての牛乳を\nたっぷり使ったプリンなの～\nマヒルに手伝ってもらって\nミヤコ直々に搾ってきたの！", "エリザベス～！なの～！", 3, 122, 24, "ミルクがとっても濃厚で\nほっぺたが落ちちゃうの～♪\nこのプリンからは牧場の…\n自然の息吹を感じるの！", "マヒルのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "マヒルからやさしいヤツだって\n聞いたの。やさしさを表現\nするために奥ゆかしい甘さに\n仕上げてみたの", "私の好きな本…読んで\nもらえたらうれしいです…\nなの", 3, 123, 25, "ほのかな甘さでありながら\nしっかりとした主張も\n感じさせる\n味わい深いプリンなの", "シオリのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "牧場にいるヤツらしいの\n牛とは違うらしいの\nもふもふ気持ちいいらしいから\n食感にこだわって作ったの", "もふもふにしてあげるなの！", 3, 124, 26, "こ、これは…！口の中に入れた\n瞬間にふんわり溶けて\nなくなっちゃうの！\nその食感がやみつきなの！", "リマのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (0, 5, "いっつも寝てるやつらしいの\nぐっすり眠れる薬草をたくさん\n入れてみたの。プリンとして\nおいしくなるかはわからないの", "めんどくさいな～なの…", 3, 125, 27, "んむぅ…評価が難しい味なの…\nおいしいのはおいしいの…\nん～考えてたら…\n眠くなってきたの…", "リンのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "クレープ屋の真っ赤な人に\n教わったプリンなの\n作り方を丁寧に教えてくれて\nとっても優しい人だったの！", "プリンの権能を解放するの～！", 3, 126, 28, "プ…プリンなのにクレープの味\nがするの。味もすごく普通なの\nでも…なんだかプリンの新しい\n扉を開けそうな気がするの…！", "ラビリスタのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (0, 5, "お店に落ちてた謎のレシピの\nプリンなの。レシピの表紙には\n『お姉ちゃんの愛情たっぷり』\nって書いてあったの", "お姉ちゃんパワー全開！なの！", 3, 127, 29, "とろける食感が絶品なの～♪\n食べるとなんだか幸せな\n気持ちになれるの…これが\n愛情ってやつなの？", "シズルのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "リノから作り方を教わったの！\nさすがクレープ屋で働いてる\nだけあって美味しそうなの！", "お兄ちゃん、プリンをよこすの！", 3, 128, 30, "これで妹力？があがるらしいの。\n妹になればお兄ちゃんに\nプリンをたかり放題なの！\n最高なの～！", "リノのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "プリンのレシピで悩んでたら\n通りすがりのおねーさんが\n一緒に考えてくれたプリンなの\nいいヤツもたまにはいるの～♪", "困った時はお互いさまさま！\nなの！", 3, 129, 31, "食べたら元気が湧いてくるの\nだからプリンのレシピのお礼に\nミヤコも人助けを手伝って\nやったの。ミヤコはえらいの！", "ヒヨリのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "ミヤコががんばって作った\nこだわりのプリンなの～\nプリンは癒しなの。だから優しい\n気持ちで丁寧に作ったの", "フラワリングヒールなの～♪", 3, 130, 32, "はっ…思わずお花畑が見えたの\n身も心も包まれるような\nとっても優しい味がするの\nこれは…まさに癒しなの～♪", "ユイのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "究極のプリンを作るため\nミヤコは厳しい修行をしたの…\nその結果あって完成した\nクールで完璧なプリンなの！", "スラッシュテンペスト！なの。", 3, 131, 33, "確かに完璧なプリンなの\nでも究極のプリンと呼ぶには\nまだまだ修行が必要なの…\nプリン作りは奥が深いの…！", "レイのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "豪華で高級な\nお嬢様プリンなの\n中には宝石みたいな\n大きいイチゴを入れるの！", "おーほっほほほ！なの！", 3, 132, 34, "味にも素材にもこだわりが\nあるの。一流は妥協しないの\nもっと豪華に、もっとおいしく\nできるはず…", "アキノのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "外はしっかり、中はふわとろの\nプリンにするの\n泡みたいなしゅわしゅわの\n生クリームも入れるの♪", "プリしゅわ最高～！なの！", 3, 133, 35, "プリンは飲み物とも言うの\nぐいっていってみるの\n…ふわしゅわでとろけるの～！\n体に染みわたるの～", "ユカリのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "餡子を入れて\nオーブンでこんがり焼くの\nたい…焼きプリンなの\n斬新なの！", "にゃにゃにゃ！なの！", 3, 134, 36, "このプリンは焼きたてのうちに\n食べるのが一番なの…！\n熱いけどおいしくて\nうずうずしてきたの…！", "タマキのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (0, 5, "栄養バランスを考えて\n木の実をたくさん入れるの\nあれこれ忙しいときでも\n頼りになるプリンなの！", "効率全開！なの！", 3, 135, 37, "プリンはいつでも手軽に\n食べられるのも魅力なの\nこれは食べ応えもあるから一つ\n食べればいっぱい動けるの", "ミフユのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "エルフの森で子どもにもらった\n薬草を使って作ったの\nこんな優しい味のプリンは\n初めてなの…", "あらあら～なの～♪", 3, 136, 38, "このプリンを食べてから\nいい子になった気がするの\n大好きなプリンを泣いてる子に\nあげたの。いい気分なの", "ミサトのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "お昼寝でみた夢の中に\nでてきた不思議なプリンを\n作ってみたの。見てたらまた\n眠くなってきたの…", "スヤスヤ～…なの…", 3, 137, 39, "あまいプリンが口の中で\nぽんぽん弾ける未知の味なの！\n今なら不思議な力で世界も\n救えそうなの！でも眠くなるの…", "ハツネのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "お店のはしっこに一つだけ\n残ったおもちゃを見て思い\nついたの。他のプリンと一緒に\n置いておくと震えだすの", "ぼっちは卒業なの～！", 3, 138, 40, "知らないうちにはしっこに\n隠れちゃってたの。食べたら\nミヤコ、シノブたちに会いに\nいきたくなってきたの", "アオイのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "トップオブアイドルの\nプリンなの。キラキラした\nものを入れて、あつ～い\nオーブンで焼いてみたの", "リズムあげるのー！", 3, 139, 41, "口の中に華やかな甘さが\n広がる…これがアイドルなの？\n急に歌って踊りたく\nなってきたの！", "ノゾミのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "ミヤコにプリンをくれるすごく\nいいヤツのプリンなの\n精霊に呼びかけながら\n一生懸命かき混ぜたの", "風の加護を！なの！", 3, 140, 42, "プリンの生地がとっても\nなめらかで最高の舌触りなの！\n精霊、ミヤコのプリンのために…", "チカのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "歌って踊って衣装も作れるヤツ\nのプリンなの。このプリンは\nきれいに包装するの。プリンを\n最高の形で着飾らせるの", "騎士さんのために\nしたんじゃありません！なの！", 3, 141, 43, "包装は食べるまでの手間が\n増えてめんどくさいの。でも\nそのめんどくささもプリンの\n味を引き立てるの", "ツムギのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (0, 5, "プリンをくれないならどうでも\nいいヤツなの。でも横で\nいろいろ言ってきたから\nがんばって作ったの", "宴の始まりなの！", 3, 142, 12, "んむっ！？\nく、口のなかでプリンの\nおいしさが大暴れなの！\n止まらないの！", "クリスティーナのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "大人な甘さ控えめのプリンを\n作るの。試しにお魚を入れて\nみるの。プリンの可能性は\n無限大なの！", "一刀両断、覚悟しな！なの！", 3, 143, 44, "大人の味なの。今やミヤコは\nみんなの頼れる姐御なの！\n悪さするやつはミヤコが\n許さないの！", "ルカのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "サイカワサイツヨな\n魔法のプリンなの\n中身をカラフルにするの～\n甘いプリンは頭が冴えるの！", "きゅぴーん！キタコレ！なの！", 3, 144, 45, "一口食べる度に味が変わって\n魔法みたいなの！\nもしかして全部食べたら\nミヤコも魔法少女になれるの？", "ナナカのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "小難しい言葉をささやきながら\n作ったら魔力あふれるプリンが\n爆誕したの！でも、不思議と\nイタイタしいのはなぜなの～？", "人呼んで、疾風のミヤコなの！", 3, 145, 46, "一口食べたら謎の組織に\n狙われたり、前世の記憶が蘇る\n気がするの～設定盛りすぎなの\nミヤコは、ミヤコは…", "アンナのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "甘酸っぱい赤い木の実を\n切り刻んで入れるの\n甘くてちょっぴり刺激的な\nヤンデレのプリンなの", "クスクス…クスクスクス…なの", 3, 146, 47, "なんか普通のプリンよりも\nいい匂いがするの～…\nプリンのことがもっともっと\n好きになっちゃうの…", "エリコのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "健康に気を遣うミヤコは\nプリンにお薬を入れてみたの～\nでもなんだか毒々しいから\n彩りにバラを添えてみたの～", "どんなプリンも\nミヤコの隻眼からは\n逃れられないの～！", 3, 147, 48, "鼻に抜ける薬のにおいがアレ\nだけど大人っぽくて頭が\nよくなった気がするの。無性に\n実験したくてしかたないの", "ミツキのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "小さいけどしっかりした\n軍人のプリンなの\nちょっと固めにして\n砂糖はいっぱい入れるの", "私は子どもではない！なの！", 3, 148, 49, "ん～王道なプリンは\n甘くて安定したおいしさなの～\n思わず笑顔になっちゃうの\nにこにこなの～♪…はっ！", "モニカのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "オーエド町で手に入れた素材と\nトーゴクに伝わる術をかけて\nプリンを作るの。シュババ！\n忍法隠し味の術なの！", "ショーグン！　ミヤコと一緒に\n天下統一するデースなの！", 3, 149, 50, "このプリンを食べてから\n誰かにお仕えしなきゃ\nいけない気がするデースなの\nそれはショ、ショー…", "ニノンのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (0, 5, "オマエが持ってきた手錠を\nヒントに作ったプリンなの\nプリンが動けないように\nカチカチに固めたの", "…ぐふふ、じゅるり～なの", 3, 150, 51, "カチカチに固めたせいで食感が\nプリンのようで\nプリンじゃないの…でもこの\nもどかしさが癖になるの…", "クウカのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "とっても美しいプリンなの\n美しいものを手当たり次第\n入れたらすごいことになったの", "あぁ、ミヤコはなんて美しいの～", 3, 151, 52, "味も美しい以外の感想が\n出てこないの。ていうかこれを\n食べたミヤコも美しいの！\n鏡、鏡はどこなの！", "ユキのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (0, 5, "知らないうちにお菓子が売れた\n時に思いついたプリンなの。\n作り方もよく覚えてない…\nけど、きっとおいしいの！", "ジー…ってミヤコなにしてるの\nミヤコはストーカーじゃないの！", 3, 152, 53, "うん、やっぱりおいしく…\nん？あそこにいるのは\nアイツなの。あれ？\n体が勝手にアイツの方に…", "アユミのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (0, 5, "イタズラ好きの手下と一緒に\n作ったプリンなの。見た目は\nかわいいけど、作り方は\n意外と複雑なの～", "にひひ…イタズラの時間なの！", 3, 153, 54, "見た目通り甘々で優しい味なの\nでも、レシピを見たら裏面に\n別の作り方が書いてあるの。\nこれだと激辛プリンに…", "ミソギのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (0, 5, "素直でやさしい手下と一緒に\n動物のぬいぐるみをいっぱい\n並べて作ったの", "ぴょんぴょこぴょーん、なの♪", 3, 154, 55, "ん～、ふわふわの甘々なの！\nなんだか楽しくなって\n心も体もるんたったしてくるの", "ミミのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (0, 5, "幽霊を怖がっている手下と\n一緒に作ったプリンなの。\n小さいクセにきっちりしてて\nとってもかわいいプリンなの", "へんたいふしんしゃさんなの！", 3, 155, 56, "ひんやりしてて暑い日でも\nおいしく食べられそうなの！\nん？これを買いたい大人が\nいる？それって…", "キョウカのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "カリスマモデルなプリンなの\nモリモリにデコレーションして\nカリスマ感を演出したの", "ハート狙い撃ち！なの！", 3, 156, 57, "見て食べて楽しめる新機軸の\nプリンなの。ミヤコは幽霊\nだけど自分の足でランウェイを\n歩きたくなってきたの！", "スズナのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (0, 5, "学校の先生をしてるヤツの\nプリンなの。お堅くしようと\nしたら、いつの間にか色っぽく\nなっちゃったの。なんでなの？", "授業を始めます♪なの！", 3, 157, 58, "プ、プリンは全部ミヤコのもの\nなのに、なんだかこのプリンは\nいろんな人に教えたく\nなっちゃう不思議な味なの！", "イオのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "少し背伸びしたおませな子を\n表現したプリンなの。あえて\n甘さ控えめなの。カラメルは\n後乗せできるから安心するの", "立派なレディ、なの！", 3, 158, 59, "ミヤコはプリンならどんなもの\nでも食べるの。でもカラメルを\nちょっとだけ足すの。\nちょっとだけなら…", "ミサキのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "謎に包まれたプリンができたの\n何か隠してるようなの…\nこれは危険なプリンなの！", "プリンを持ってこないと\nお仕置きだよ～☆なの！", 3, 159, 60, "味はすごいゴージャスなの！\nボスの風格があるの！\nビッグなミヤコに\nプリンを捧げるの！", "ホマレのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "ワイルドな見た目なの！\nこれは期待できそうなの。\nきっと躍動感あふれる味なの！", "たぎってきたの！", 3, 160, 61, "最初の一口目が\nすごいインパクトなの！\n無性にケンカしたくなるの！\nプリンをよこせなの！", "カヤのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (0, 5, "なんか見た目がパッとしないの\nこれほんとに大丈夫なの？\nなんか頼りないの…", "下剋上、やってやるですなの！", 3, 161, 62, "見た目はアレだけど味はおいし\nいの…あと主張もはっきりして\nるの！やる気と自信だけは\n出てきたのうおおおーなの！", "イノリのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "天下の大悪党のプリンなの\nこれまでのジョーシキに\n捉われないプリンを\n作ってみたの～", "どけどけ～！なの～！", 3, 162, 63, "むむむ…食べたら\nやる気が湧いてきたの！\nミヤコを邪魔するやつはみんな\nまとめてぶっ飛ばしてやるの～", "ムイミのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "いろんなものに変身したり\n分身したりできるヤツの\nプリンなの。型で同じプリンを\nたくさんたくさん作ったの", "ミラーミラー！なの！", 3, 163, 64, "いつのまにか作ったの全部\n食べちゃったの。なんで\nプリンは分身しないの？\n無限に増えろなの！", "ネネカのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "金の亡者のプリンなの\n金にものを言わせて作って\nみたの。おばあちゃんの\nプリンと対極なの", "プリンに忠誠を誓いますわ！\nなの！", 3, 164, 65, "むぅ…認めたくないけど\nおいしいの…これを何個も\n作れるほどのお金を稼ぐのは\n大変なの…でもおいしいから…", "クレジッタのプリン");
INSERT INTO `v1_00f82b37a570be84ea0f355a3c25bb52d4a171bd87d81ed44dca4e75ff2eb35b` VALUES (1, 5, "みんなお世話になるギルド\n管理協会職員のプリンなの\nお役所感を出すために手堅く\n王道に作ったの", "ギルド管理協会へようこそ！\nなの！", 3, 165, 66, "手堅い…！手堅いの…！\n隙のないプリンなの！\n今のミヤコなら完璧な\n書類作成ができそうなの！", "カリンのプリン");
